// Get email data from Gmail Trigger
const fromRaw = $input.first().json.From || $input.first().json.from || '';
const senderMatch = fromRaw.match(/<(.+?)>/);
const sender = senderMatch ? senderMatch[1] : fromRaw.trim();

const body = $input.first().json.text
  || $input.first().json.snippet
  || $input.first().json.body
  || '';

const subject = $input.first().json.Subject
  || $input.first().json.subject
  || '';

const threadId = $input.first().json.id || '';

// Extract order number
const orderMatch = body.match(/order\s*#?\s*(\d+)/i)
  || body.match(/#(\d+)/)
  || body.match(/\b(\d{4,6})\b/);
const orderNumber = orderMatch ? orderMatch[1] : 'UNKNOWN';

// Detect return reason
const reasons = ['damaged', 'wrong item', 'not as described', 'late', 'defective', 'broken', 'faulty'];
const reason = reasons.find(r => body.toLowerCase().includes(r)) || 'unspecified';

// Detect escalation keywords
const escalationWords = ['trading standards', 'solicitor', 'legal action', 'court', 'report you', 'consumer rights'];
const needsEscalation = escalationWords.some(w => body.toLowerCase().includes(w));

// Fake order database (replace with real DB in production)
const orders = {
  '12345': '2026-05-01',  // within 30 days → AUTO
  '67890': '2026-03-01',  // outside 30 days → GATE
  '11111': '2026-04-30',  // within 30 days → AUTO
};

const orderDate = orders[orderNumber];
let withinWindow = false;

if (orderDate) {
  const diffDays = (new Date() - new Date(orderDate)) / (1000 * 60 * 60 * 24);
  withinWindow = diffDays <= 30;
} else {
  // No order found — default to WITHIN
  withinWindow = true;
}

return [{ json: { orderNumber, reason, sender, threadId, body, subject, needsEscalation, withinWindow } }];

